void popStackToClose(String elName) {
    // Find the rightmost (topmost) element with the given name and pop everything above it and the element itself
    // Use a single pass from the top, but pop efficiently from the end
    int targetIndex = -1;
    // First pass: find the topmost occurrence of the element to close
    for (int pos = stack.size() - 1; pos >= 0; pos--) {
        if (stack.get(pos).nodeName().equals(elName)) {
            targetIndex = pos;
            break;
        }
    }

    if (targetIndex != -1) {
        // Now remove all elements from top of stack down to and including targetIndex
        int elementsToRemove = stack.size() - targetIndex;
        for (int i = 0; i < elementsToRemove; i++) {
            stack.remove(stack.size() - 1); // Remove from end, which is O(1)
        }
    }
}

